import React, { useState, useEffect } from 'react';
import { Camera, Image as ImageIcon, Video, Mail, Phone, MapPin, Menu, X, ChevronRight, Globe, Maximize2, MessageCircle, CheckCircle2 } from 'lucide-react';

// Custom Instagram Icon
const InstagramIcon = ({ className }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <rect x="2" y="2" width="20" height="20" rx="5" ry="5"></rect>
    <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path>
    <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"></line>
  </svg>
);

const App = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [lang, setLang] = useState('ar');
  const [selectedGallery, setSelectedGallery] = useState(null);

  // --- HAYDE EL-KHITWE EL-AHAMM ---
  // Bi-tkhalli el-suwar tiftah 3andak locally w 3al GitHub Pages
  const getAssetPath = (path) => {
    const publicUrl = process.env.PUBLIC_URL || '';
    return `${publicUrl}${path}`;
  };

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const content = {
    en: {
      nav: ['Services', 'Portfolio', 'Contact'],
      hero: {
        title: 'Capturing Moments, Telling Stories',
        subtitle: 'Professional photography and video production for your most precious memories.',
        cta: 'Book a Session'
      },
      services: {
        title: 'Our Services',
        items: [
          { 
            title: 'Commercial', 
            desc: 'High-end product and brand photography.', 
            icon: <Camera />, 
            img: getAssetPath('/img/service1.jpg') // Zabbatt el-path hon
          },
          { 
            title: 'Events', 
            desc: 'Coverage for weddings, parties, and corporate events.', 
            icon: <ImageIcon />, 
            img: getAssetPath('/img/service2.jpg') 
          },
          { 
            title: 'Video Production', 
            desc: 'Cinematic storytelling for any occasion.', 
            icon: <Video />, 
            img: getAssetPath('/img/service3.jpg') 
          }
        ]
      },
      // ... Kel el-content el-ba'i metel ma huwe bi-malafak ...
    },
    ar: {
      nav: ['خدماتنا', 'أعمالنا', 'اتصل بنا'],
      hero: {
        title: 'نخلد اللحظات.. لنروي القصص',
        subtitle: 'تصوير احترافي وإنتاج فيديو لأثمن ذكرياتكم بأعلى جودة.',
        cta: 'احجز جلستك الآن'
      },
      services: {
        title: 'خدماتنا',
        items: [
          { title: 'التصوير التجاري', desc: 'تصوير المنتجات والعلامات التجارية باحترافية.', icon: <Camera />, img: getAssetPath('/img/service1.jpg') },
          { title: 'المناسبات', desc: 'تغطية كاملة للأعراس، الحفلات والمناسبات الخاصة.', icon: <ImageIcon />, img: getAssetPath('/img/service2.jpg') },
          { title: 'إنتاج الفيديو', desc: 'صناعة محتوى مرئي يحكي قصتكم بأسلوب سينمائي.', icon: <Video />, img: getAssetPath('/img/service3.jpg') }
        ]
      }
    }
  };

  return (
    <div className={`min-h-screen bg-[#0a0a0a] text-white font-sans ${lang === 'ar' ? 'rtl' : 'ltr'}`}>

      {/* Hero Section */}
      <section id="home" className="relative h-screen flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src={getAssetPath('/img/hero.jpg')} // Zabbatt el-path hon kman
            alt="Hero Background" 
            className="w-full h-full object-cover opacity-50 scale-105 animate-slow-zoom"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-[#0a0a0a]/50 via-transparent to-[#0a0a0a]" />
        </div>
        {/* ... ba2i el-JSX kello metel malafak el-asli ... */}
      </section>

      {/* ... Kaffi kel el-sections metel ma kinto ... */}

    </div>
  );
};

export default App;
